import{_ as t,o,c as n,a2 as a}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"RFC 0015 — Notification Center","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0015-notification-center.md","filePath":"rfcs/0015-notification-center.md"}'),i={name:"rfcs/0015-notification-center.md"};function s(r,e,d,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="rfc-0015-—-notification-center" tabindex="-1">RFC 0015 — Notification Center <a class="header-anchor" href="#rfc-0015-—-notification-center" aria-label="Permalink to &quot;RFC 0015 — Notification Center&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/sdk</code> (<code>sdk.notifications</code>), <code>packages/manifest</code> (<code>notifications:send</code>), platform DB (<code>packages/db</code> — a new <code>notifications</code> table + notification prefs), runtime chrome + API routes, <code>packages/ui</code> (new <code>Toast</code> + popover/panel), Account (notification prefs), Console (admin broadcast), SRS; builds on RFC 0005 (activity log), RFC 0011 (icon system), RFC 0013 (mobile Drawer)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.7.0; documentation-first. This RFC specifies the in-app notification system (data model, SDK surface, UI, delivery) and the end-to-end flows. SRS requirement IDs (proposed <code>NOTIF-*</code>), scheduling, and task allocation are deferred. <strong>Web Push is a separate RFC 0016</strong> that layers a background delivery channel on top of this one.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Give Sovereign a <strong>Notification Center</strong>: a per-user, persistent place to see everything that happened — a plugin finished a job, an admin posted an announcement, the platform flagged a security event. The system has four parts:</p><ul><li>a tenant-scoped, per-user <strong>inbox</strong> (a <code>notifications</code> table) with read/unread/dismiss state;</li><li>the fleshed-out <strong><code>sdk.notifications</code> write surface</strong> (today a reserved <code>NotImplementedError</code> stub) that lets a plugin deliver a notification to a user;</li><li>a <strong>bell + panel</strong> in the shell chrome (desktop sidebar, mobile header) showing an unread badge and the notification list;</li><li><strong>toasts</strong> — transient in-app pop-ups for notifications that arrive while the user is actively using the app.</li></ul><p><strong>Core principle:</strong> plugins never render UI or pick a delivery channel. A plugin calls <code>sdk.notifications.send</code>; the <strong>platform owns fan-out</strong> — it always writes the inbox row, shows a toast if the user is active, and (RFC 0016) sends a push if they&#39;re subscribed and the category is allowed. Delivery policy, abuse limits, and transport stay entirely platform-controlled.</p><p>This is the <strong>in-app foundation</strong> and is shippable on its own; Web Push (RFC 0016) is optional and additive.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The notifications surface is <strong>declared but unimplemented</strong>: <code>sdk.notifications.send(userId, message)</code> throws <code>NotImplementedError</code> (<code>packages/sdk/src/unimplemented.ts:18–22</code>) and <code>notifications:send</code> is reserved in the permission enum (<code>packages/manifest/src/schema.ts:15</code>, SRS §3.6). There is <strong>no data model, no UI, and no delivery</strong> — a plugin that finishes a long task, or an admin who needs to tell everyone about scheduled downtime, has no channel to the user. A self-hosted workspace that holds someone&#39;s working life needs a single, glanceable place for &quot;what needs my attention.&quot;</p><h2 id="relationship-to-the-activity-log-rfc-0005" tabindex="-1">Relationship to the Activity Log (RFC 0005) <a class="header-anchor" href="#relationship-to-the-activity-log-rfc-0005" aria-label="Permalink to &quot;Relationship to the Activity Log (RFC 0005)&quot;">​</a></h2><p>These are <strong>separate systems</strong> and must not be conflated:</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Activity Log (RFC 0005)</th><th>Notification Center (this RFC)</th></tr></thead><tbody><tr><td>Purpose</td><td>Durable <strong>audit trail</strong> of what happened</td><td><strong>Actionable alerts</strong> directed <em>to</em> a user</td></tr><tr><td>Visibility</td><td>Derived by view (personal feed + admin-wide)</td><td><strong>Recipient-scoped</strong> (the notification&#39;s target user)</td></tr><tr><td>Lifecycle</td><td><strong>Append-only</strong>, never mutated</td><td><strong>Mutable</strong> — read / dismissed by the user</td></tr><tr><td>Dispatch</td><td>None — read on demand</td><td><strong>Actively delivered</strong> (badge, toast, later push)</td></tr><tr><td>Shape</td><td>actor/subject/action/target/metadata</td><td>title / body / action URL / category / read state</td></tr></tbody></table><p>They <strong>intersect</strong> in exactly one place: an admin broadcast (below) is <strong>audited into the activity log</strong> for accountability. Otherwise the inbox is its own table with its own lifecycle; this RFC deliberately does <strong>not</strong> reuse <code>activity_log</code>.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Reserved stub + permission</strong> — <code>sdk.notifications.send(userId, message)</code> (<code>packages/sdk/src/unimplemented.ts:18–22</code>, exported via <code>packages/sdk/src/index.ts</code>); <code>notifications:send</code> in the enum (<code>packages/manifest/src/schema.ts:9–22</code>). This RFC implements that reserved surface, the same way RFC 0005 implements <code>sdk.activity</code>.</li><li><strong>Chrome popover pattern</strong> — <code>runtime/app/(platform)/_components/AccountMenu.tsx</code> is a keyboard-accessible popover (open state, <code>aria-expanded</code>, Esc, click-outside, <code>placement: &#39;sidebar&#39; | &#39;header&#39;</code>). The bell mirrors it.</li><li><strong>Bell slot</strong> — the shell renders a bottom <code>.chrome</code> group (Console gear + avatar) in the desktop sidebar and an avatar in the mobile header (<code>runtime/app/(platform)/layout.tsx:46–60</code>, <code>shell.module.css</code>).</li><li><strong>No primitives yet</strong> — <code>packages/ui</code> ships only Button/Input/Dialog; there is no Badge, Popover, or Toast. The bell icon comes from RFC 0011&#39;s <code>&lt;Icon&gt;</code> (<code>&lt;Icon name=&quot;bell&quot;&gt;</code>); the mobile panel can use RFC 0013&#39;s Drawer.</li><li><strong>Platform settings + prefs patterns</strong> — instance settings live in <code>platform_settings</code> (<code>invite_only</code>, <code>root_plugin_id</code>), read via <code>sdk.platform.getConfig()</code>; per-user prefs live in <code>account_prefs</code>. New notification settings follow these.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="data-model" tabindex="-1">Data model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data model&quot;">​</a></h3><p>A tenant-scoped <code>notifications</code> table (dialect-aware int/bigint, the <code>packages/db</code> schema/sqlite + schema/postgres + bootstrap-DDL + parity-test pattern):</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><code>id</code></td><td>ULID/uuid</td></tr><tr><td><code>tenant_id</code></td><td>tenant scope (single-tenant default in v1)</td></tr><tr><td><code>recipient_user_id</code></td><td>who sees it</td></tr><tr><td><code>source</code></td><td>the plugin id, or <code>platform</code>, or <code>admin</code></td></tr><tr><td><code>source_type</code></td><td><code>plugin</code> | <code>platform</code> | <code>admin</code> (set by the runtime, not forgeable)</td></tr><tr><td><code>title</code></td><td>short headline</td></tr><tr><td><code>body</code></td><td>optional longer text</td></tr><tr><td><code>url</code></td><td>optional action target (in-app route)</td></tr><tr><td><code>category</code></td><td>e.g. <code>info</code> | <code>announcement</code> | <code>security</code> (drives mute prefs)</td></tr><tr><td><code>icon</code></td><td>optional <code>&lt;Icon&gt;</code> name override</td></tr><tr><td><code>read_at</code></td><td>null until read</td></tr><tr><td><code>dismissed_at</code></td><td>null until dismissed</td></tr><tr><td><code>created_at</code></td><td>unix seconds</td></tr></tbody></table><p>Indexes: <code>(tenant_id, recipient_user_id, created_at)</code> and an unread lookup. A small <strong>notification prefs</strong> store (per-category mute, e.g. mute <code>announcement</code>; plus the per-user <strong>poll interval</strong>, see transport) — an <code>account_prefs</code> extension or a <code>notification_prefs</code> table.</p><h3 id="sdk-surface" tabindex="-1">SDK surface <a class="header-anchor" href="#sdk-surface" aria-label="Permalink to &quot;SDK surface&quot;">​</a></h3><p>Flesh out the reserved stub into a real, send-only surface:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.notifications.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  recipientUserId: string,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  notification: { title: string; body</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> string; url</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> string; category</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> string; icon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> string },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;void&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>The runtime injects <code>source</code> (the calling plugin&#39;s id), <code>source_type = &#39;plugin&#39;</code>, and <code>tenant_id</code> — a plugin cannot forge another source or impersonate <code>platform</code>/ <code>admin</code>. Gated by the existing <strong><code>notifications:send</code></strong> permission. <strong>Send-only for plugins:</strong> reading, marking-read, and dismissing are platform UI concerns, not an SDK surface in v1 (a plugin has no business reading a user&#39;s full inbox). Adoption mirrors RFC 0005: the reserved stub becomes a real implementation as an <strong>additive minor</strong> SDK + manifest bump, no breaking change.</p><p>The <strong>runtime itself</strong> emits notifications (e.g. a security notice) through an internal helper — not via the public SDK.</p><h3 id="delivery-fan-out-platform-owned" tabindex="-1">Delivery fan-out (platform-owned) <a class="header-anchor" href="#delivery-fan-out-platform-owned" aria-label="Permalink to &quot;Delivery fan-out (platform-owned)&quot;">​</a></h3><p>On every new notification the platform:</p><ol><li><strong>writes the inbox row</strong> (always);</li><li>emits a <strong>toast</strong> if the recipient is currently active in the app;</li><li>(RFC 0016) sends a <strong>Web Push</strong> if the recipient is subscribed and the category isn&#39;t muted.</li></ol><p>The plugin/runtime caller does none of this routing — it only calls <code>send</code>.</p><h3 id="foreground-real-time-transport-—-two-implementations-admin-selectable" tabindex="-1">Foreground real-time transport — two implementations, admin-selectable <a class="header-anchor" href="#foreground-real-time-transport-—-two-implementations-admin-selectable" aria-label="Permalink to &quot;Foreground real-time transport — two implementations, admin-selectable&quot;">​</a></h3><p>How the bell learns about a new notification while the app is open is configurable; <strong>both</strong> transports are specified and shipped:</p><ul><li><strong>Polling</strong> — the bell client polls the unread endpoint on an interval. Simple, no persistent connection, works behind any reverse proxy with zero extra config.</li><li><strong>WebSocket</strong> — a persistent server→client channel for instant delivery. (<strong>SSE / <code>EventSource</code></strong> is noted as the lighter one-way alternative — the traffic is server→client only, so SSE may suffice; the implementation evaluates the tradeoff. WebSocket/SSE both require the reverse proxy to allow long-lived / upgrade connections.)</li></ul><p>An <strong>admin platform setting</strong> — <code>notification_transport: &#39;polling&#39; | &#39;websocket&#39;</code> in <code>platform_settings</code>, read via <code>sdk.platform.getConfig()</code> — selects the method <strong>instance-wide</strong>, defaulting to <strong>polling</strong> (the safest choice for arbitrary self-host networking). This follows the existing <code>invite_only</code> / <code>root_plugin_id</code> settings pattern.</p><p><strong>Account setting — poll interval.</strong> In polling mode, each user can set their <strong>poll interval</strong> (e.g. 15 s / 30 s / 60 s, with a sensible minimum clamp) in the Account notification prefs; the value is ignored when the admin has selected WebSocket.</p><h3 id="ui-—-bell-panel-toast" tabindex="-1">UI — bell, panel, toast <a class="header-anchor" href="#ui-—-bell-panel-toast" aria-label="Permalink to &quot;UI — bell, panel, toast&quot;">​</a></h3><ul><li><strong>Bell</strong> — a new client component mirroring <code>AccountMenu</code>: on <strong>desktop</strong> it sits in the sidebar bottom <code>.chrome</code> between the Console gear and the avatar (popover opens up-and-right); on <strong>mobile</strong> it sits in the header next to the avatar. It renders <code>&lt;Icon name=&quot;bell&quot;&gt;</code> (RFC 0011) with an <strong>unread badge</strong>.</li><li><strong>Panel</strong> — the popover content: notifications grouped by unread/read, each linking to its <code>url</code>, with mark-read, dismiss, and mark-all-read. On small screens the panel is presented as a <strong>Drawer</strong> (RFC 0013) rather than a popover.</li><li><strong>Toast</strong> — a new <code>packages/ui</code> primitive: transient, auto-dismissing, stacking, rendered in an ARIA live region (<code>role=&quot;status&quot;</code> / <code>aria-live=&quot;polite&quot;</code>), tokens only (no hardcoded values). Proposed alongside a small reusable <strong>Popover</strong> primitive (or, if preferred, the bell reuses the <code>AccountMenu</code> pattern directly). Both are additive design-system additions.</li><li><strong>API routes</strong> under the reserved <code>account</code> segment (session-gated by the middleware-injected user headers): <code>GET /api/account/notifications</code> (list + unread count), <code>POST …/read</code>, <code>POST …/dismiss</code>.</li></ul><h3 id="admin-broadcast" tabindex="-1">Admin broadcast <a class="header-anchor" href="#admin-broadcast" aria-label="Permalink to &quot;Admin broadcast&quot;">​</a></h3><p>A Console action lets an admin post an <strong><code>announcement</code></strong>-category notification to <strong>every instance user</strong> (creating one inbox row per recipient; toasts for the active ones). Because this is the one capability that can reach everyone, it is <strong>guarded on all four axes</strong>:</p><ul><li><strong>Audited</strong> — each broadcast is recorded in the RFC 0005 activity log (who, when, audience, message) for accountability.</li><li><strong>Rate-limited</strong> — a cap on broadcast frequency so a careless or compromised admin can&#39;t spam every user repeatedly.</li><li><strong>Audience-scoped</strong> — admins target only their own instance&#39;s users, and only via this platform broadcast path; there is <strong>no</strong> API for an admin to inject an arbitrary per-user notification that impersonates a plugin or the platform.</li><li><strong>User opt-out respected</strong> — users may mute the announcement category, except a small reserved <strong>critical-security</strong> class that always delivers.</li></ul><p>(Push delivery of broadcasts is extended in RFC 0016, under the same guardrails.)</p><h2 id="ui-flows" tabindex="-1">UI flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI flows&quot;">​</a></h2><p><strong>Plugin notifies a user</strong> — plugin calls <code>sdk.notifications.send(userId, …)</code> → the platform writes the inbox row → the bell&#39;s unread badge increments → if the user is active, a toast appears → opening the bell shows the notification; clicking it navigates to <code>url</code> and marks it read; the user can dismiss it.</p><p><strong>Admin broadcast</strong> — admin opens Console → composes an announcement → confirms → every user gets an <code>announcement</code> notification (audited to the activity log); active users see a toast. A user who has muted announcements gets no toast/badge for it (unless it&#39;s the reserved critical class).</p><p><strong>Transport selection</strong> — admin sets <code>notification_transport</code> to <code>websocket</code> in Console → clients receive notifications instantly; or leaves it <code>polling</code> (default) → each user&#39;s bell polls at their configured interval.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Ephemeral / client-only store</strong> (local storage, session-scoped). Rejected — &quot;show all my notifications&quot; and cross-device unread state require server persistence.</li><li><strong>Reuse the <code>activity_log</code> table.</strong> Rejected — different lifecycle (mutable vs append-only), visibility (recipient vs derived views), and shape. Conflating them would compromise both. They intersect only via broadcast auditing.</li><li><strong>A modal Dialog for the panel.</strong> Rejected — a notification list is a glanceable, non-blocking surface; a popover (desktop) / Drawer (mobile) is correct, not a scrim-backed modal.</li><li><strong>Let plugins render toasts / manage delivery directly.</strong> Rejected — that hands delivery policy and abuse control to untrusted plugin code. Plugins write to the inbox; the platform decides everything else.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Retention</strong> — auto-prune read/dismissed notifications after N days to bound table growth on long-lived instances, or keep everything?</li><li><strong>WebSocket vs SSE</strong> — since traffic is server→client only, SSE may be the better &quot;WebSocket&quot; implementation; decide at build time (both are documented here).</li><li><strong>Poll-interval minimum</strong> — the smallest interval a user may choose (server-side clamp) to bound load.</li><li><strong>Plugin targeting</strong> — may a plugin notify <strong>any</strong> tenant user, or only users who have interacted with that plugin? (Tighter scoping reduces abuse.)</li><li><strong>Badge semantics</strong> — unread count vs &quot;has unread&quot;; cap display at e.g. <code>9+</code>.</li><li><strong>Requirement IDs</strong> — proposed <code>NOTIF-*</code> entries, not assigned in the SRS until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong> Design + flows captured; no code, no SRS edits, no scheduling.</li><li><strong>When accepted &amp; scheduled:</strong> the <code>notifications</code> table + prefs, the <code>sdk.notifications.send</code> implementation (replacing the stub — additive minor SDK bump), the bell + panel + the new <code>Toast</code>/<code>Popover</code> primitives, the <code>account</code>-segment API routes, the admin broadcast + guardrails, and the admin-selectable transport (polling + WebSocket/SSE) with the per-user poll interval.</li><li><strong>RFC 0016 — Web Push</strong> follows: background delivery of these same inbox notifications when the app isn&#39;t foregrounded.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; per-user inbox + <code>sdk.notifications</code> send surface + bell/panel/toast UI + admin broadcast (four guardrails) + admin-selectable polling/WebSocket transport; documentation-first, Web Push split to RFC 0016.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.7.0.</td></tr></tbody></table>`,53)])])}const u=t(i,[["render",s]]);export{g as __pageData,u as default};
